import threading

class Task:
    def __init__(self, task_id, description, assigned_to, due_date):
        self.task_id = task_id
        self.description = description
        self.assigned_to = assigned_to
        self.due_date = due_date
        self.completed = False

    def mark_completed(self):
        self.completed = True

    def __str__(self):
        status = "Completed" if self.completed else "Pending"
        return f"Task ID: {self.task_id}, Description: {self.description}, Assigned to: {self.assigned_to}, Due Date: {self.due_date}, Status: {status}"

class ProjectOrganizer:
    def __init__(self):
        self.tasks = {}
        self.lock = threading.Lock()

    def create_task(self, task_id, description, assigned_to, due_date):
        with self.lock:
            if task_id in self.tasks:
                return f"Task ID {task_id} already exists."
            self.tasks[task_id] = Task(task_id, description, assigned_to, due_date)
            return f"Task ID {task_id} created successfully."

    def get_task(self, task_id):
        with self.lock:
            return self.tasks.get(task_id, f"Task ID {task_id} not found.")

    def mark_task_completed(self, task_id):
        with self.lock:
            task = self.tasks.get(task_id)
            if task:
                task.mark_completed()
                return f"Task ID {task_id} marked as completed."
            return f"Task ID {task_id} not found."

    def list_tasks(self):
        with self.lock:
            return "\n".join(str(task) for task in self.tasks.values())

    def real_time_updates(self):
        def update_checker():
            while True:
                with self.lock:
                    for task_id, task in self.tasks.items():
                        if not task.completed and task.due_date < datetime.datetime.now():
                            print(f"Alert: Task ID {task_id} is overdue.")
                time.sleep(60)  # Check every minute

        threading.Thread(target=update_checker, daemon=True).start()

# Example usage
