    organizer = ProjectOrganizer()
    organizer.create_task(1, "Design database schema", "Alice", datetime.datetime.now() + datetime.timedelta(days=3))
    organizer.create_task(2, "Implement user authentication", "Bob", datetime.datetime.now() + datetime.timedelta(days=5))
